// Extraer y validar datos de la solicitud de cita
const body = $input.first().json.body || $input.first().json;

const fecha = body.fecha;
const hora = body.hora;
const psicologoId = body.psicologo_id;
const modalidad = body.modalidad || 'presencial';
const reporteCifrado = body.reporte_cifrado || null;
const correoAnonimo = body.correo_anonimo || null;

// Validaciones basicas
if (!fecha || !hora || !psicologoId) {
  throw new Error('Datos incompletos: se requiere fecha, hora y psicologo_id');
}

// Construir fecha/hora para Google Calendar
const startDateTime = `${fecha}T${hora}:00`;
const [horaNum, minNum] = hora.split(':').map(Number);
const endMinutes = minNum + 50; // Sesion de 50 minutos
const endHour = horaNum + Math.floor(endMinutes / 60);
const endMin = endMinutes % 60;
const endTime = `${String(endHour).padStart(2, '0')}:${String(endMin).padStart(2, '0')}`;
const endDateTime = `${fecha}T${endTime}:00`;

// Mapeo de psicologos a calendarios
const calendarMap = {
  'psi-001': 'psi001@kallpa.edu.pe',
  'psi-002': 'psi002@kallpa.edu.pe',
  'psi-003': 'psi003@kallpa.edu.pe',
  'psi-004': 'psi004@kallpa.edu.pe'
};

const calendarId = calendarMap[psicologoId] || 'primary';

// Mapeo de psicologos a nombres
const nameMap = {
  'psi-001': 'Dra. Martinez',
  'psi-002': 'Lic. Rodriguez',
  'psi-003': 'Dr. Huaman',
  'psi-004': 'Lic. Quispe'
};

const psicologoNombre = nameMap[psicologoId] || 'Psicologo';

// Generar ID unico para la cita
const citaId = `cita-${Date.now()}-${Math.random().toString(36).substring(2, 7)}`;

return {
  json: {
    citaId,
    fecha,
    hora,
    endTime,
    startDateTime,
    endDateTime,
    psicologoId,
    psicologoNombre,
    calendarId,
    modalidad,
    reporteCifrado,
    correoAnonimo,
    titulo: `Cita Bienestar - ${modalidad}`,
    descripcion: `Sesion de bienestar universitario\nModalidad: ${modalidad}\nPsicologo: ${psicologoNombre}`
  }
};

// Preparar respuesta exitosa
const extractData = $('Extraer Datos').item.json;
const calendarEvent = $('Crear Evento Calendar').item.json;

return {
  json: {
    cita_id: extractData.citaId,
    status: 'confirmado',
    mensaje: 'Cita agendada exitosamente',
    fecha: extractData.fecha,
    hora_inicio: extractData.hora,
    hora_fin: extractData.endTime,
    psicologo: extractData.psicologoNombre,
    modalidad: extractData.modalidad,
    calendar_event_id: calendarEvent.id || null,
    email_enviado: true
  }
};

// Respuesta sin email
const extractData = $('Extraer Datos').item.json;
const calendarEvent = $('Crear Evento Calendar').item.json;

return {
  json: {
    cita_id: extractData.citaId,
    status: 'confirmado',
    mensaje: 'Cita agendada exitosamente (sin correo de confirmacion)',
    fecha: extractData.fecha,
    hora_inicio: extractData.hora,
    hora_fin: extractData.endTime,
    psicologo: extractData.psicologoNombre,
    modalidad: extractData.modalidad,
    calendar_event_id: calendarEvent.id || null,
    email_enviado: false
  }
};
